function getInitialTerminalFontSize() {
  if (typeof window === 'undefined') {
    return terminalDefaultFontSize;
  }

  try {
    const savedValue = window.localStorage.getItem(terminalFontSizeStorageKey);
    if (savedValue === null) {
      return terminalDefaultFontSize;
    }

    return normalizeTerminalFontSize(Number(savedValue));
  } catch {
    return terminalDefaultFontSize;
  }
}

function normalizeTerminalFontSize(value: number) {
  if (!Number.isFinite(value)) {
    return terminalDefaultFontSize;
  }

  return Math.min(
    terminalMaxFontSize,
    Math.max(terminalMinFontSize, Math.round(value))
  );
}

function isTerminalAtBottom(element: HTMLElement) {
  return (
    element.scrollHeight - element.clientHeight - element.scrollTop <=
    terminalFollowThresholdPx
  );
}

function scrollTerminalToBottom(element: HTMLElement) {
  element.scrollTop = element.scrollHeight;
}

function getTerminalStatusLabel(status: TerminalConnectionStatus) {
  switch (status) {
    case 'connected':
      return 'Connected';
    case 'connecting':
      return 'Connecting';
    case 'disconnected':
      return 'Disconnected';
    case 'failed':
      return 'Connection failed';
    case 'unsupported':
      return 'Terminal unavailable';
    case 'idle':
      return 'Idle';
  }
}

function getTerminalStatusClassName(status: TerminalConnectionStatus) {
  switch (status) {
    case 'connected':
      return 'bg-emerald-500';
    case 'connecting':
      return 'animate-pulse bg-amber-400';
    case 'disconnected':
    case 'failed':
      return 'bg-red-500';
    case 'unsupported':
      return 'bg-muted-foreground';
    case 'idle':
      return 'bg-muted-foreground/70';
  }
}

function measureTerminalSize(element: HTMLElement): TerminalSize | undefined {
  const rect = element.getBoundingClientRect();
  if (rect.width <= 0 || rect.height <= 0) {
    return undefined;
  }

  const row = document.createElement('div');
  row.className = 'term-row';
  row.style.position = 'absolute';
  row.style.visibility = 'hidden';
  row.style.pointerEvents = 'none';
  row.style.whiteSpace = 'pre';
  row.style.top = '0';
  row.style.left = '0';

  const probe = document.createElement('span');
  probe.textContent = 'W';
  row.appendChild(probe);
  element.appendChild(row);

  const charWidth = probe.getBoundingClientRect().width;
  const rowHeight = row.getBoundingClientRect().height;
  row.remove();

  if (charWidth <= 0 || rowHeight <= 0) {
    return undefined;
  }

  const style = getComputedStyle(element);
  const paddingX =
    toPixelNumber(style.paddingLeft) + toPixelNumber(style.paddingRight);
  const paddingY =
    toPixelNumber(style.paddingTop) + toPixelNumber(style.paddingBottom);
  const availableWidth = element.clientWidth - paddingX;
  const availableHeight = element.clientHeight - paddingY;

  if (availableWidth <= 0 || availableHeight <= 0) {
    return undefined;
  }

  return {
    cols: Math.max(1, Math.floor(availableWidth / charWidth)),
    rows: Math.max(1, Math.floor(availableHeight / rowHeight)),
  };
}

function toPixelNumber(value: string) {
  const parsed = Number.parseFloat(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function IconButton(props: {
  label: string;
  children: ReactNode;
  disabled?: boolean;
  onClick?: () => void;
}) {
  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <Button
            type="button"
            variant="secondary"
            size="icon"
            className="size-9 rounded-none shadow-none"
            aria-label={props.label}
            disabled={props.disabled}
            onClick={props.onClick}
          />
        }
      >
        {props.children}
      </TooltipTrigger>
      <TooltipContent>
        <p>{props.label}</p>
      </TooltipContent>
    </Tooltip>
  );
}

function writeTerminalMessage(terminal: WTerm, data: unknown) {
  if (typeof data === 'string') {
    terminal.write(data);
    return;
  }

  if (data instanceof ArrayBuffer) {
    terminal.write(new Uint8Array(data));
    return;
  }

  if (data instanceof Blob) {
    void data.arrayBuffer().then((buffer) => {
      terminal.write(new Uint8Array(buffer));
    });
  }
}

