import {
  BellIcon,
  LayoutDashboardIcon,
  MonitorIcon,
  RotateCcwIcon,
  SaveIcon,
  SettingsIcon,
  TerminalIcon,
} from 'lucide-react';
import { useCallback, useId, useMemo, useState } from 'react';

import { cn } from '@/lib/tailwind/utils';

import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Dialog,
  DialogBody,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';

import type { HomeView } from '@/features/home/components/molecules/session-view-tabs';

export type HomeSettingsDialogSaveState = 'idle' | 'saving' | 'error';
export type HomeSettingsTheme = 'system' | 'light' | 'dark';
export type HomeSettingsSidebarDefault = 'remember' | 'open' | 'collapsed';
export type HomeSettingsTerminalScale = 'compact' | 'standard' | 'large';
export type HomeSettingsTerminalScrollback = 'standard' | 'extended';
export type HomeSettingsDensity = 'comfortable' | 'compact';

export interface HomeSettingsValues {
  autoFollowTerminal: boolean;
  defaultView: HomeView;
  density: HomeSettingsDensity;
  notifyOnCompletion: boolean;
  notifyOnPrompt: boolean;
  sidebarDefault: HomeSettingsSidebarDefault;
  terminalScale: HomeSettingsTerminalScale;
  terminalScrollback: HomeSettingsTerminalScrollback;
  theme: HomeSettingsTheme;
}

export const defaultHomeSettingsValues: HomeSettingsValues = {
  autoFollowTerminal: true,
  defaultView: 'kanban',
  density: 'compact',
  notifyOnCompletion: true,
  notifyOnPrompt: true,
  sidebarDefault: 'remember',
  terminalScale: 'standard',
  terminalScrollback: 'standard',
  theme: 'system',
};

const settingsTabs = [
  { icon: LayoutDashboardIcon, label: 'Workspace', value: 'workspace' },
  { icon: TerminalIcon, label: 'Terminal', value: 'terminal' },
  { icon: BellIcon, label: 'Notifications', value: 'notifications' },
] as const;

const defaultViewOptions = [
  { label: 'Kanban', value: 'kanban' },
  { label: 'Terminal', value: 'terminal' },
] satisfies Array<{ label: string; value: HomeView }>;

const themeOptions = [
  { label: 'System', value: 'system' },
  { label: 'Light', value: 'light' },
  { label: 'Dark', value: 'dark' },
] satisfies Array<{ label: string; value: HomeSettingsTheme }>;

const sidebarDefaultOptions = [
  { label: 'Remember last state', value: 'remember' },
  { label: 'Open', value: 'open' },
  { label: 'Collapsed', value: 'collapsed' },
] satisfies Array<{ label: string; value: HomeSettingsSidebarDefault }>;

const densityOptions = [
  { label: 'Comfortable', value: 'comfortable' },
  { label: 'Compact', value: 'compact' },
] satisfies Array<{ label: string; value: HomeSettingsDensity }>;

const terminalScaleOptions = [
  { label: 'Compact', value: 'compact' },
  { label: 'Standard', value: 'standard' },
  { label: 'Large', value: 'large' },
] satisfies Array<{ label: string; value: HomeSettingsTerminalScale }>;

const terminalScrollbackOptions = [
  { label: 'Standard', value: 'standard' },
  { label: 'Extended', value: 'extended' },
] satisfies Array<{ label: string; value: HomeSettingsTerminalScrollback }>;

export function HomeSettingsDialog(props: {
  baselineValues?: HomeSettingsValues;
  className?: string;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  onReset?: (values: HomeSettingsValues) => void;
  onSave?: (values: HomeSettingsValues) => void;
  onValuesChange?: (values: HomeSettingsValues) => void;
  saveError?: string;
  saveState?: HomeSettingsDialogSaveState;
  triggerClassName?: string;
  values?: HomeSettingsValues;
}) {
  const [uncontrolledSavedValues, setUncontrolledSavedValues] = useState(
    props.baselineValues ?? props.values ?? defaultHomeSettingsValues
  );
  const [uncontrolledValues, setUncontrolledValues] = useState(
    props.values ??
      props.baselineValues ??
      uncontrolledSavedValues ??
      defaultHomeSettingsValues
  );
  const [activeTab, setActiveTab] =
    useState<(typeof settingsTabs)[number]['value']>('workspace');
  const values = props.values ?? uncontrolledValues;
  const baselineValues = props.baselineValues ?? uncontrolledSavedValues;
  const saveState = props.saveState ?? 'idle';
  const isSaving = saveState === 'saving';
  const hasChanges = useMemo(
    () => !areHomeSettingsValuesEqual(values, baselineValues),
    [baselineValues, values]
  );

  const updateValues = useCallback(
    (updates: Partial<HomeSettingsValues>) => {
      const nextValues = { ...values, ...updates };

      if (!props.values) {
        setUncontrolledValues(nextValues);
      }
      props.onValuesChange?.(nextValues);
    },
    [props, values]
  );

  const handleSave = useCallback(() => {
    if (!hasChanges || isSaving) {
      return;
    }

    props.onSave?.(values);
    if (!props.baselineValues) {
      setUncontrolledSavedValues(values);
    }
  }, [hasChanges, isSaving, props, values]);

  const handleReset = useCallback(() => {
    if (isSaving) {
      return;
    }

    if (!props.values) {
      setUncontrolledValues(baselineValues);
    }
    props.onReset?.(baselineValues);
    props.onValuesChange?.(baselineValues);
  }, [baselineValues, isSaving, props]);

  return (
    <Dialog defaultOpen={props.defaultOpen} onOpenChange={props.onOpenChange}>
      <DialogTrigger
        render={
          <Button
            type="button"
            variant="secondary"
            size="icon"
            className={cn('size-9 rounded-none shadow-none', props.triggerClassName)}
            aria-label="Settings"
          />
        }
      >
        <SettingsIcon />
        <span className="sr-only">Settings</span>
      </DialogTrigger>
      <DialogContent
        className={cn(
          'max-h-[calc(100vh-2rem)] gap-0 overflow-hidden rounded-none p-0 sm:max-w-2xl',
          props.className
        )}
      >
        <DialogHeader className="border-b border-border px-5 py-4">
          <div className="flex min-w-0 items-center gap-3">
            <DialogTitle className="truncate">Settings</DialogTitle>
            <SettingsStateBadge hasChanges={hasChanges} saveState={saveState} />
          </div>
          <DialogDescription>Local workspace defaults.</DialogDescription>
        </DialogHeader>

        <DialogBody className="max-h-[min(680px,calc(100vh-11rem))] overflow-y-auto px-5 py-4">
          {saveState === 'error' ? (
            <Alert variant="destructive" className="mb-4 rounded-none">
              <AlertTitle>Settings not saved</AlertTitle>
              <AlertDescription>
                {props.saveError ?? 'Review the highlighted settings and try again.'}
              </AlertDescription>
            </Alert>
          ) : null}

          <Tabs
            value={activeTab}
            onValueChange={(nextTab) => {
              if (isSettingsTab(nextTab)) {
                setActiveTab(nextTab);
              }
            }}
          >
            <TabsList
              variant="line"
              className="w-full justify-start overflow-x-auto rounded-none p-0"
            >
              {settingsTabs.map((tab) => {
                const TabIcon = tab.icon;

                return (
                  <TabsTrigger
                    key={tab.value}
                    value={tab.value}
                    className="min-w-0 rounded-none px-3"
                  >
                    <TabIcon />
                    {tab.label}
                  </TabsTrigger>
                );
              })}
            </TabsList>

            <TabsContent value="workspace" className="pt-4">
              <SettingsSection>
                <SelectSettingRow
                  id={useStableId('default-view')}
                  label="Startup view"
                  options={defaultViewOptions}
                  value={values.defaultView}
                  onValueChange={(defaultView) => {
                    updateValues({ defaultView });
                  }}
                />
                <Separator />
                <SelectSettingRow
                  id={useStableId('sidebar-default')}
                  label="Project sidebar"
                  options={sidebarDefaultOptions}
                  value={values.sidebarDefault}
                  onValueChange={(sidebarDefault) => {
                    updateValues({ sidebarDefault });
                  }}
                />
                <Separator />
                <SelectSettingRow
                  id={useStableId('theme')}
                  label="Theme"
                  options={themeOptions}
                  value={values.theme}
                  onValueChange={(theme) => {
                    updateValues({ theme });
                  }}
                />
                <Separator />
                <SelectSettingRow
                  id={useStableId('density')}
                  label="Density"
                  options={densityOptions}
                  value={values.density}
                  onValueChange={(density) => {
                    updateValues({ density });
                  }}
                />
              </SettingsSection>
            </TabsContent>

            <TabsContent value="terminal" className="pt-4">
              <SettingsSection>
                <SelectSettingRow
                  id={useStableId('terminal-scale')}
                  label="Terminal type size"
                  options={terminalScaleOptions}
                  value={values.terminalScale}
                  onValueChange={(terminalScale) => {
                    updateValues({ terminalScale });
                  }}
                />
                <Separator />
                <SelectSettingRow
                  id={useStableId('terminal-scrollback')}
                  label="Scrollback"
                  options={terminalScrollbackOptions}
                  value={values.terminalScrollback}
                  onValueChange={(terminalScrollback) => {
                    updateValues({ terminalScrollback });
                  }}
                />
                <Separator />
                <CheckboxSetting
                  checked={values.autoFollowTerminal}
                  description="Keep the terminal pinned to the latest output."
                  disabled={isSaving}
                  label="Auto-follow output"
                  onCheckedChange={(autoFollowTerminal) => {
                    updateValues({ autoFollowTerminal });
                  }}
                />
              </SettingsSection>
            </TabsContent>

            <TabsContent value="notifications" className="pt-4">
              <SettingsSection>
                <CheckboxSetting
                  checked={values.notifyOnPrompt}
                  description="Show an alert when a worker needs input."
                  disabled={isSaving}
                  label="Prompt handoff"
                  onCheckedChange={(notifyOnPrompt) => {
                    updateValues({ notifyOnPrompt });
                  }}
                />
                <Separator />
                <CheckboxSetting
                  checked={values.notifyOnCompletion}
                  description="Show an alert when a worker reaches Done."
                  disabled={isSaving}
                  label="Worker completion"
                  onCheckedChange={(notifyOnCompletion) => {
                    updateValues({ notifyOnCompletion });
                  }}
                />
              </SettingsSection>
            </TabsContent>
          </Tabs>
        </DialogBody>

        <DialogFooter className="border-t border-border px-5 py-4">
          <Button
            type="button"
            variant="ghost"
            disabled={!hasChanges || isSaving}
            onClick={handleReset}
          >
            <RotateCcwIcon data-icon="inline-start" />
            Revert
          </Button>
          <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
            <DialogClose render={<Button type="button" variant="secondary" />}>
              Cancel
            </DialogClose>
            <Button
              type="button"
              loading={isSaving}
              disabled={!hasChanges || isSaving}
              onClick={handleSave}
            >
              <SaveIcon data-icon="inline-start" />
              {isSaving ? 'Saving' : 'Save changes'}
            </Button>
          </div>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function SettingsSection(props: { children: React.ReactNode }) {
  return <div className="flex flex-col gap-4">{props.children}</div>;
}

function SelectSettingRow<TValue extends string>(props: {
  id: string;
  label: string;
  onValueChange: (value: TValue) => void;
  options: Array<{ label: string; value: TValue }>;
  value: TValue;
}) {
  return (
    <div className="grid min-w-0 gap-2 sm:grid-cols-[minmax(0,1fr)_12rem] sm:items-center">
      <label htmlFor={props.id} className="text-sm font-medium text-foreground">
        {props.label}
      </label>
      <Select
        items={props.options}
        value={props.value}
        onValueChange={(value) => {
          if (typeof value === 'string') {
            props.onValueChange(value as TValue);
          }
        }}
      >
        <SelectTrigger id={props.id} className="rounded-none">
          <SelectValue />
        </SelectTrigger>
        <SelectContent align="end">
          <SelectGroup>
            {props.options.map((option) => (
              <SelectItem key={option.value} value={option.value}>
                {option.label}
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    </div>
  );
}

function CheckboxSetting(props: {
  checked: boolean;
  description: string;
  disabled?: boolean;
  label: string;
  onCheckedChange: (checked: boolean) => void;
}) {
  return (
    <Checkbox
      checked={props.checked}
      disabled={props.disabled}
      labelProps={{
        className: 'items-start',
      }}
      onCheckedChange={(checked) => {
        props.onCheckedChange(checked === true);
      }}
    >
      <span className="flex min-w-0 flex-col gap-0.5">
        <span className="text-sm font-medium text-foreground">{props.label}</span>
        <span className="text-xs text-muted-foreground">{props.description}</span>
      </span>
    </Checkbox>
  );
}

function SettingsStateBadge(props: {
  hasChanges: boolean;
  saveState: HomeSettingsDialogSaveState;
}) {
  if (props.saveState === 'saving') {
    return (
      <Badge variant="warning" size="sm">
        Saving
      </Badge>
    );
  }

  if (props.saveState === 'error') {
    return (
      <Badge variant="negative" size="sm">
        Needs attention
      </Badge>
    );
  }

  if (props.hasChanges) {
    return (
      <Badge variant="warning" size="sm">
        Unsaved changes
      </Badge>
    );
  }

  return (
    <Badge variant="positive" size="sm">
      Saved
    </Badge>
  );
}

function areHomeSettingsValuesEqual(
  left: HomeSettingsValues,
  right: HomeSettingsValues
) {
  return (
    left.autoFollowTerminal === right.autoFollowTerminal &&
    left.defaultView === right.defaultView &&
    left.density === right.density &&
    left.notifyOnCompletion === right.notifyOnCompletion &&
    left.notifyOnPrompt === right.notifyOnPrompt &&
    left.sidebarDefault === right.sidebarDefault &&
    left.terminalScale === right.terminalScale &&
    left.terminalScrollback === right.terminalScrollback &&
    left.theme === right.theme
  );
}

function isSettingsTab(
  value: string
): value is (typeof settingsTabs)[number]['value'] {
  return settingsTabs.some((tab) => tab.value === value);
}

function useStableId(name: string) {
  return `${useId()}-${name}`;
}

