import type { Meta, StoryObj } from '@storybook/tanstack-react';
import { expect, fn, userEvent, within } from 'storybook/test';

import { SidebarProvider } from '@/components/ui/sidebar';

import { MainTopbar } from '@/features/home/components/organisms/main-topbar';

const meta = {
  title: 'Home/Main Topbar',
  component: MainTopbar,
  parameters: {
    layout: 'fullscreen',
  },
  decorators: [
    (Story) => (
      <div className="bg-background font-mono text-foreground">
        <SidebarProvider defaultOpen={false}>
          <Story />
        </SidebarProvider>
      </div>
    ),
  ],
  args: {
    onViewChange: fn(),
    view: 'kanban',
  },
} satisfies Meta<typeof MainTopbar>;

export default meta;

type Story = StoryObj<typeof meta>;

export const Default: Story = {
  play: async ({ args, canvas, canvasElement }) => {
    await expect(canvas.getByRole('tab', { name: 'Kanban' })).toHaveAttribute(
      'aria-selected',
      'true'
    );

    await userEvent.click(canvas.getByRole('tab', { name: 'Terminal' }));
    await expect(args.onViewChange).toHaveBeenCalledWith('terminal');

    await userEvent.click(canvas.getByRole('button', { name: 'Settings' }));
    const body = within(canvasElement.ownerDocument.body);
    await expect(
      body.getByRole('dialog', { name: 'Settings' })
    ).toBeVisible();
  },
};

export const TerminalSelected: Story = {
  args: {
    view: 'terminal',
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('tab', { name: 'Terminal' })).toHaveAttribute(
      'aria-selected',
      'true'
    );
  },
};

