  onValueChange: (value: TValue) => void;
  options: Array<{ label: string; value: TValue }>;
  value: TValue;
}) {
  return (
    <div className="grid min-w-0 gap-2 sm:grid-cols-[minmax(0,1fr)_12rem] sm:items-center">
      <label htmlFor={props.id} className="text-sm font-medium text-foreground">
        {props.label}
      </label>
      <Select
        items={props.options}
        value={props.value}
        onValueChange={(value) => {
          if (typeof value === 'string') {
            props.onValueChange(value as TValue);
          }
        }}
      >
        <SelectTrigger id={props.id} className="rounded-none">
          <SelectValue />
        </SelectTrigger>
        <SelectContent align="end">
          <SelectGroup>
            {props.options.map((option) => (
              <SelectItem key={option.value} value={option.value}>
                {option.label}
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    </div>
  );
}

function CheckboxSetting(props: {
  checked: boolean;
  description: string;
  disabled?: boolean;
  label: string;
  onCheckedChange: (checked: boolean) => void;
}) {
  return (
    <Checkbox
      checked={props.checked}
      disabled={props.disabled}
      labelProps={{
        className: 'items-start',
      }}
      onCheckedChange={(checked) => {
        props.onCheckedChange(checked === true);
      }}
    >
      <span className="flex min-w-0 flex-col gap-0.5">
        <span className="text-sm font-medium text-foreground">
          {props.label}
        </span>
        <span className="text-xs text-muted-foreground">
          {props.description}
        </span>
      </span>
    </Checkbox>
  );
}

function SettingsStateBadge(props: {
  hasChanges: boolean;
  saveState: HomeSettingsDialogSaveState;
}) {
  if (props.saveState === 'saving') {
    return (
      <Badge variant="warning" size="sm">
        Saving
      </Badge>
    );
  }

  if (props.saveState === 'error') {
    return (
      <Badge variant="negative" size="sm">
        Needs attention
      </Badge>
    );
  }

  if (props.hasChanges) {
    return (
      <Badge variant="warning" size="sm">
        Unsaved changes
      </Badge>
    );
  }

  return (
    <Badge variant="positive" size="sm">
      Saved
    </Badge>
  );
}

function areHomeSettingsValuesEqual(
  left: HomeSettingsValues,
  right: HomeSettingsValues
) {
  return (
    left.autoFollowTerminal === right.autoFollowTerminal &&
    left.defaultView === right.defaultView &&
    left.density === right.density &&
    left.notifyOnCompletion === right.notifyOnCompletion &&
    left.notifyOnPrompt === right.notifyOnPrompt &&
    left.sidebarDefault === right.sidebarDefault &&
    left.terminalScale === right.terminalScale &&
    left.terminalScrollback === right.terminalScrollback &&
    left.theme === right.theme
  );
}

function isSettingsTab(
  value: string
): value is (typeof settingsTabs)[number]['value'] {
  return settingsTabs.some((tab) => tab.value === value);
}

