      await page.getByRole('dialog', { name: 'Settings' }).waitFor();
      if (!(await page.getByText('Saving').first().isVisible())) throw new Error('Saving badge missing');
      if (!(await page.getByRole('button', { name: 'Saving' }).isDisabled())) throw new Error('Saving button should be disabled');
    },
  },
  {
    id: 'home-settings-dialog--save-error',
    check: async (page) => {
      await page.getByRole('dialog', { name: 'Settings' }).waitFor();
      await page.getByRole('alert').waitFor();
      if (!(await page.getByText('Unable to write local workspace settings.').isVisible())) throw new Error('Error text missing');
    },
  },
  {
    id: 'home-settings-dialog--trigger-closed',
