    await page.goto(`${baseUrl}${story.id}&viewMode=story`, { waitUntil: 'domcontentloaded' });
    await story.check(page);
    if (errors.length > 0) {
      throw new Error(`${story.id} console errors: ${errors.join('\n')}`);
    }
    await page.close();
  }
} finally {
  await browser.close();
}
