export type HomeSettingsDialogSaveState = 'idle' | 'saving' | 'error';
export type HomeSettingsTheme = 'system' | 'light' | 'dark';
export type HomeSettingsSidebarDefault = 'remember' | 'open' | 'collapsed';
export type HomeSettingsTerminalScale = 'compact' | 'standard' | 'large';
export type HomeSettingsTerminalScrollback = 'standard' | 'extended';
export type HomeSettingsDensity = 'comfortable' | 'compact';

export interface HomeSettingsValues {
  autoFollowTerminal: boolean;
  defaultView: HomeView;
  density: HomeSettingsDensity;
  notifyOnCompletion: boolean;
  notifyOnPrompt: boolean;
  sidebarDefault: HomeSettingsSidebarDefault;
  terminalScale: HomeSettingsTerminalScale;
  terminalScrollback: HomeSettingsTerminalScrollback;
  theme: HomeSettingsTheme;
}

export const defaultHomeSettingsValues: HomeSettingsValues = {
  autoFollowTerminal: true,
  defaultView: 'kanban',
  density: 'compact',
  notifyOnCompletion: true,
  notifyOnPrompt: true,
  sidebarDefault: 'remember',
  terminalScale: 'standard',
  terminalScrollback: 'standard',
  theme: 'system',
};

const settingsTabs = [
  { icon: LayoutDashboardIcon, label: 'Workspace', value: 'workspace' },
  { icon: TerminalIcon, label: 'Terminal', value: 'terminal' },
  { icon: BellIcon, label: 'Notifications', value: 'notifications' },
] as const;

const defaultViewOptions = [
  { label: 'Kanban', value: 'kanban' },
  { label: 'Terminal', value: 'terminal' },
] satisfies Array<{ label: string; value: HomeView }>;

const themeOptions = [
  { label: 'System', value: 'system' },
  { label: 'Light', value: 'light' },
  { label: 'Dark', value: 'dark' },
] satisfies Array<{ label: string; value: HomeSettingsTheme }>;

const sidebarDefaultOptions = [
  { label: 'Remember last state', value: 'remember' },
  { label: 'Open', value: 'open' },
  { label: 'Collapsed', value: 'collapsed' },
] satisfies Array<{ label: string; value: HomeSettingsSidebarDefault }>;

const densityOptions = [
  { label: 'Comfortable', value: 'comfortable' },
  { label: 'Compact', value: 'compact' },
] satisfies Array<{ label: string; value: HomeSettingsDensity }>;

const terminalScaleOptions = [
  { label: 'Compact', value: 'compact' },
  { label: 'Standard', value: 'standard' },
  { label: 'Large', value: 'large' },
] satisfies Array<{ label: string; value: HomeSettingsTerminalScale }>;

const terminalScrollbackOptions = [
  { label: 'Standard', value: 'standard' },
  { label: 'Extended', value: 'extended' },
] satisfies Array<{ label: string; value: HomeSettingsTerminalScrollback }>;

export function HomeSettingsDialog(props: {
  baselineValues?: HomeSettingsValues;
  className?: string;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  onReset?: (values: HomeSettingsValues) => void;
  onSave?: (values: HomeSettingsValues) => void;
  onValuesChange?: (values: HomeSettingsValues) => void;
  saveError?: string;
  saveState?: HomeSettingsDialogSaveState;
  triggerClassName?: string;
  values?: HomeSettingsValues;
