    if (isSaving) {
      return;
    }

    if (!props.values) {
      setUncontrolledValues(baselineValues);
    }
    props.onReset?.(baselineValues);
    props.onValuesChange?.(baselineValues);
  }, [baselineValues, isSaving, props]);

  return (
    <Dialog defaultOpen={props.defaultOpen} onOpenChange={props.onOpenChange}>
      <DialogTrigger
        render={
          <Button
            type="button"
            variant="secondary"
            size="icon"
            className={cn(
              'size-9 rounded-none shadow-none',
              props.triggerClassName
            )}
            aria-label="Settings"
          />
        }
