import type { Meta, StoryObj } from '@storybook/tanstack-react';
import { expect, fn, userEvent, within } from 'storybook/test';

import {
  defaultHomeSettingsValues,
  HomeSettingsDialog,
  type HomeSettingsValues,
} from '@/features/home/components/organisms/home-settings-dialog';

const dirtySettingsValues = {
  ...defaultHomeSettingsValues,
  autoFollowTerminal: false,
  defaultView: 'terminal',
  density: 'comfortable',
  notifyOnCompletion: false,
  sidebarDefault: 'open',
  terminalScale: 'large',
  terminalScrollback: 'extended',
  theme: 'dark',
} satisfies HomeSettingsValues;

const meta = {
  title: 'Home/Settings Dialog',
  component: HomeSettingsDialog,
  parameters: {
    layout: 'centered',
  },
  decorators: [
    (Story) => (
      <div className="min-h-[720px] bg-background p-8 font-mono text-foreground">
        <Story />
      </div>
    ),
  ],
} satisfies Meta<typeof HomeSettingsDialog>;

export default meta;

type Story = StoryObj<typeof meta>;

export const Saved: Story = {
  args: {
    defaultOpen: true,
  },
  play: async ({ canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByRole('dialog', { name: 'Settings' })).toBeVisible();
    await expect(body.getByText('Saved')).toBeVisible();
    await expect(
      body.getByRole('button', { name: 'Save changes' })
    ).toBeDisabled();
  },
};

export const UnsavedChanges: Story = {
  args: {
    baselineValues: defaultHomeSettingsValues,
    defaultOpen: true,
    onSave: fn(),
    values: dirtySettingsValues,
  },
  play: async ({ args, canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByText('Unsaved changes')).toBeVisible();
    await userEvent.click(body.getByRole('button', { name: 'Save changes' }));
    await expect(args.onSave).toHaveBeenCalledWith(dirtySettingsValues);
  },
};

export const Saving: Story = {
  args: {
    baselineValues: defaultHomeSettingsValues,
    defaultOpen: true,
    saveState: 'saving',
    values: dirtySettingsValues,
  },
  play: async ({ canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByRole('button', { name: 'Saving' })).toBeDisabled();
  },
};

export const SaveError: Story = {
  args: {
    baselineValues: defaultHomeSettingsValues,
    defaultOpen: true,
    saveError: 'Unable to write local workspace settings.',
    saveState: 'error',
    values: dirtySettingsValues,
  },
  play: async ({ canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByRole('alert')).toBeVisible();
    await expect(body.getByText('Needs attention')).toBeVisible();
    await expect(
      body.getByText('Unable to write local workspace settings.')
    ).toBeVisible();
  },
};

export const TriggerClosed: Story = {
  args: {
    onOpenChange: fn(),
  },
  play: async ({ args, canvas, canvasElement }) => {
    await userEvent.click(canvas.getByRole('button', { name: 'Settings' }));
    await expect(args.onOpenChange).toHaveBeenCalledWith(
      true,
      expect.anything()
    );

    const body = within(canvasElement.ownerDocument.body);
    await expect(body.getByRole('dialog', { name: 'Settings' })).toBeVisible();
  },
};

