import type { Meta, StoryObj } from '@storybook/tanstack-react';
import { expect, fn, userEvent, within } from 'storybook/test';

import {
  defaultWorkspacePreferencesValues,
  WorkspacePreferencesDialog,
  type WorkspacePreferencesValues,
} from '@/features/home/components/organisms/workspace-preferences-dialog';

const dirtyPreferencesValues = {
  ...defaultWorkspacePreferencesValues,
  autoFollowTerminal: false,
  defaultView: 'terminal',
  notifyOnCompletion: false,
  sidebarDefault: 'open',
  terminalScale: 'large',
  theme: 'dark',
} satisfies WorkspacePreferencesValues;

const meta = {
  title: 'Home/Workspace Preferences Dialog',
  component: WorkspacePreferencesDialog,
  parameters: {
    layout: 'centered',
  },
  decorators: [
    (Story) => (
      <div className="min-h-[720px] bg-background p-8 font-mono text-foreground">
        <Story />
      </div>
    ),
  ],
} satisfies Meta<typeof WorkspacePreferencesDialog>;

export default meta;

type Story = StoryObj<typeof meta>;

export const Saved: Story = {
  args: {
    defaultOpen: true,
  },
  play: async ({ canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByRole('dialog', { name: 'Settings' })).toBeVisible();
    await expect(body.getByText('Saved')).toBeVisible();
    await expect(
      body.getByRole('button', { name: 'Save changes' })
    ).toBeDisabled();
  },
};

export const UnsavedChanges: Story = {
  args: {
    baselineValues: defaultWorkspacePreferencesValues,
    defaultOpen: true,
    onSave: fn(),
    values: dirtyPreferencesValues,
  },
  play: async ({ args, canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByText('Unsaved changes')).toBeVisible();
    await userEvent.click(body.getByRole('button', { name: 'Save changes' }));
    await expect(args.onSave).toHaveBeenCalledWith(dirtyPreferencesValues);
  },
};

export const Saving: Story = {
  args: {
    baselineValues: defaultWorkspacePreferencesValues,
    defaultOpen: true,
    saveState: 'saving',
    values: dirtyPreferencesValues,
  },
  play: async ({ canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByText('Saving')).toBeVisible();
    await expect(body.getByRole('button', { name: 'Saving' })).toBeDisabled();
    await expect(body.getByRole('button', { name: 'Revert' })).toBeDisabled();
  },
};

export const SaveError: Story = {
  args: {
    baselineValues: defaultWorkspacePreferencesValues,
    defaultOpen: true,
    saveError: 'Could not write preferences. Try again after reconnecting.',
    saveState: 'error',
    values: dirtyPreferencesValues,
  },
  play: async ({ canvasElement }) => {
    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByText('Needs attention')).toBeVisible();
    await expect(body.getByRole('alert')).toHaveTextContent(
      'Could not write preferences'
    );
    await expect(
      body.getByRole('button', { name: 'Save changes' })
    ).toBeEnabled();
  },
};

export const TriggerClosed: Story = {
  args: {
    onOpenChange: fn(),
  },
  play: async ({ args, canvas, canvasElement }) => {
    await userEvent.click(canvas.getByRole('button', { name: 'Settings' }));

    await expect(args.onOpenChange).toHaveBeenCalledWith(true, expect.anything());

    const body = within(canvasElement.ownerDocument.body);

    await expect(body.getByRole('dialog', { name: 'Settings' })).toBeVisible();
  },
};

import {
  BellIcon,
  LayoutDashboardIcon,
  RotateCcwIcon,
  SaveIcon,
  SettingsIcon,
  TerminalIcon,
} from 'lucide-react';
import { type ReactNode, useCallback, useId, useMemo, useState } from 'react';

import { cn } from '@/lib/tailwind/utils';

import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Dialog,
  DialogBody,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';

import type { HomeView } from '@/features/home/components/molecules/session-view-tabs';

export type WorkspacePreferencesSaveState = 'idle' | 'saving' | 'error';
export type WorkspacePreferencesTheme = 'system' | 'light' | 'dark';
export type WorkspacePreferencesSidebarDefault =
  | 'remember'
  | 'open'
  | 'collapsed';
export type WorkspacePreferencesTerminalScale =
  | 'compact'
  | 'standard'
  | 'large';

export interface WorkspacePreferencesValues {
  autoFollowTerminal: boolean;
  defaultView: HomeView;
  notifyOnCompletion: boolean;
  notifyOnPrompt: boolean;
  sidebarDefault: WorkspacePreferencesSidebarDefault;
  terminalScale: WorkspacePreferencesTerminalScale;
  theme: WorkspacePreferencesTheme;
}

export const defaultWorkspacePreferencesValues: WorkspacePreferencesValues = {
  autoFollowTerminal: true,
  defaultView: 'kanban',
  notifyOnCompletion: true,
  notifyOnPrompt: true,
  sidebarDefault: 'remember',
  terminalScale: 'standard',
  theme: 'system',
};

const preferenceTabs = [
  { icon: LayoutDashboardIcon, label: 'Workspace', value: 'workspace' },
  { icon: TerminalIcon, label: 'Terminal', value: 'terminal' },
  { icon: BellIcon, label: 'Notifications', value: 'notifications' },
] as const;

const defaultViewOptions = [
  { label: 'Kanban', value: 'kanban' },
  { label: 'Terminal', value: 'terminal' },
] satisfies Array<{ label: string; value: HomeView }>;

const sidebarDefaultOptions = [
  { label: 'Remember last state', value: 'remember' },
  { label: 'Open', value: 'open' },
  { label: 'Collapsed', value: 'collapsed' },
] satisfies Array<{ label: string; value: WorkspacePreferencesSidebarDefault }>;

const themeOptions = [
  { label: 'System', value: 'system' },
  { label: 'Light', value: 'light' },
  { label: 'Dark', value: 'dark' },
] satisfies Array<{ label: string; value: WorkspacePreferencesTheme }>;

const terminalScaleOptions = [
  { label: 'Compact', value: 'compact' },
  { label: 'Standard', value: 'standard' },
  { label: 'Large', value: 'large' },
] satisfies Array<{ label: string; value: WorkspacePreferencesTerminalScale }>;

export function WorkspacePreferencesDialog(props: {
  baselineValues?: WorkspacePreferencesValues;
  className?: string;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  onReset?: (values: WorkspacePreferencesValues) => void;
  onSave?: (values: WorkspacePreferencesValues) => void;
  onValuesChange?: (values: WorkspacePreferencesValues) => void;
  saveError?: string;
  saveState?: WorkspacePreferencesSaveState;
  triggerClassName?: string;
  values?: WorkspacePreferencesValues;
}) {
  const [savedValues, setSavedValues] = useState(
    props.baselineValues ?? props.values ?? defaultWorkspacePreferencesValues
  );
  const [draftValues, setDraftValues] = useState(
    props.values ?? props.baselineValues ?? savedValues
  );
  const [activeTab, setActiveTab] =
    useState<(typeof preferenceTabs)[number]['value']>('workspace');
  const defaultViewId = useId();
  const sidebarDefaultId = useId();
  const themeId = useId();
  const terminalScaleId = useId();
  const values = props.values ?? draftValues;
  const baselineValues = props.baselineValues ?? savedValues;
  const saveState = props.saveState ?? 'idle';
  const isSaving = saveState === 'saving';
  const hasChanges = useMemo(
    () => !areWorkspacePreferencesValuesEqual(values, baselineValues),
    [baselineValues, values]
  );

  const updateValues = useCallback(
    (updates: Partial<WorkspacePreferencesValues>) => {
      const nextValues = { ...values, ...updates };

      if (!props.values) {
        setDraftValues(nextValues);
      }
      props.onValuesChange?.(nextValues);
    },
    [props, values]
  );

  const handleSave = useCallback(() => {
    if (!hasChanges || isSaving) {
      return;
    }

    props.onSave?.(values);
    if (!props.baselineValues) {
      setSavedValues(values);
    }
  }, [hasChanges, isSaving, props, values]);

  const handleReset = useCallback(() => {
    if (isSaving) {
      return;
    }

    if (!props.values) {
      setDraftValues(baselineValues);
    }
    props.onReset?.(baselineValues);
    props.onValuesChange?.(baselineValues);
  }, [baselineValues, isSaving, props]);

  return (
    <Dialog defaultOpen={props.defaultOpen} onOpenChange={props.onOpenChange}>
      <DialogTrigger
        render={
          <Button
            type="button"
            variant="secondary"
            size="icon"
            className={cn(
              'size-9 rounded-none shadow-none',
              props.triggerClassName
            )}
            aria-label="Settings"
          />
        }
      >
        <SettingsIcon />
        <span className="sr-only">Settings</span>
      </DialogTrigger>
      <DialogContent
        className={cn(
          'max-h-[calc(100vh-2rem)] gap-0 overflow-hidden rounded-none p-0 sm:max-w-2xl',
          props.className
        )}
      >
        <DialogHeader className="border-b border-border px-5 py-4">
          <div className="flex min-w-0 items-center gap-3">
            <DialogTitle className="truncate">Settings</DialogTitle>
            <PreferencesStateBadge
              hasChanges={hasChanges}
              saveState={saveState}
            />
          </div>
          <DialogDescription>Local workspace defaults.</DialogDescription>
        </DialogHeader>

        <DialogBody className="max-h-[min(680px,calc(100vh-11rem))] overflow-y-auto px-5 py-4">
          {saveState === 'error' ? (
            <Alert variant="destructive" className="mb-4 rounded-none">
              <AlertTitle>Settings not saved</AlertTitle>
              <AlertDescription>
                {props.saveError ??
                  'Review the highlighted settings and try again.'}
              </AlertDescription>
            </Alert>
          ) : null}

          <Tabs
            value={activeTab}
            onValueChange={(nextTab) => {
              if (isPreferenceTab(nextTab)) {
                setActiveTab(nextTab);
              }
            }}
          >
            <TabsList
              variant="line"
              className="w-full justify-start overflow-x-auto rounded-none p-0"
            >
              {preferenceTabs.map((tab) => {
                const TabIcon = tab.icon;

                return (
                  <TabsTrigger
                    key={tab.value}
                    value={tab.value}
                    className="min-w-0 rounded-none px-3"
                  >
                    <TabIcon />
                    {tab.label}
                  </TabsTrigger>
                );
              })}
            </TabsList>

            <TabsContent value="workspace" className="pt-4">
              <PreferenceSection>
                <SelectPreferenceRow
                  id={defaultViewId}
                  label="Startup view"
                  options={defaultViewOptions}
                  value={values.defaultView}
                  onValueChange={(defaultView) => updateValues({ defaultView })}
                />
                <Separator />
                <SelectPreferenceRow
                  id={sidebarDefaultId}
                  label="Project sidebar"
                  options={sidebarDefaultOptions}
                  value={values.sidebarDefault}
                  onValueChange={(sidebarDefault) =>
                    updateValues({ sidebarDefault })
                  }
                />
                <Separator />
                <SelectPreferenceRow
                  id={themeId}
                  label="Theme"
                  options={themeOptions}
                  value={values.theme}
                  onValueChange={(theme) => updateValues({ theme })}
                />
              </PreferenceSection>
            </TabsContent>

            <TabsContent value="terminal" className="pt-4">
              <PreferenceSection>
                <SelectPreferenceRow
                  id={terminalScaleId}
                  label="Terminal type size"
                  options={terminalScaleOptions}
                  value={values.terminalScale}
                  onValueChange={(terminalScale) =>
                    updateValues({ terminalScale })
                  }
                />
                <Separator />
                <CheckboxPreference
                  checked={values.autoFollowTerminal}
                  description="Keep the terminal pinned to the latest output."
                  disabled={isSaving}
                  label="Auto-follow output"
                  onCheckedChange={(autoFollowTerminal) =>
                    updateValues({ autoFollowTerminal })
                  }
                />
              </PreferenceSection>
            </TabsContent>

            <TabsContent value="notifications" className="pt-4">
              <PreferenceSection>
                <CheckboxPreference
                  checked={values.notifyOnPrompt}
                  description="Show an alert when a worker needs input."
                  disabled={isSaving}
                  label="Prompt handoff"
                  onCheckedChange={(notifyOnPrompt) =>
                    updateValues({ notifyOnPrompt })
                  }
                />
                <Separator />
                <CheckboxPreference
                  checked={values.notifyOnCompletion}
                  description="Show an alert when a worker reaches Done."
                  disabled={isSaving}
                  label="Worker completion"
                  onCheckedChange={(notifyOnCompletion) =>
                    updateValues({ notifyOnCompletion })
                  }
                />
              </PreferenceSection>
            </TabsContent>
          </Tabs>
        </DialogBody>

        <DialogFooter className="border-t border-border px-5 py-4">
          <Button
            type="button"
            variant="ghost"
            disabled={!hasChanges || isSaving}
            onClick={handleReset}
          >
            <RotateCcwIcon data-icon="inline-start" />
            Revert
          </Button>
          <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
            <DialogClose render={<Button type="button" variant="secondary" />}>
              Cancel
            </DialogClose>
            <Button
              type="button"
              loading={isSaving}
              disabled={!hasChanges || isSaving}
              onClick={handleSave}
            >
              <SaveIcon data-icon="inline-start" />
              {isSaving ? 'Saving' : 'Save changes'}
            </Button>
          </div>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function PreferenceSection(props: { children: ReactNode }) {
  return <div className="flex flex-col gap-4">{props.children}</div>;
}

function SelectPreferenceRow<TValue extends string>(props: {
  id: string;
  label: string;
  onValueChange: (value: TValue) => void;
  options: Array<{ label: string; value: TValue }>;
  value: TValue;
}) {
  return (
    <div className="grid min-w-0 gap-2 sm:grid-cols-[minmax(0,1fr)_12rem] sm:items-center">
      <label htmlFor={props.id} className="text-sm font-medium text-foreground">
        {props.label}
      </label>
      <Select
        items={props.options}
        value={props.value}
        onValueChange={(value) => {
          if (typeof value === 'string') {
            props.onValueChange(value as TValue);
          }
        }}
      >
        <SelectTrigger id={props.id} className="rounded-none">
          <SelectValue />
        </SelectTrigger>
        <SelectContent align="end">
          <SelectGroup>
            {props.options.map((option) => (
              <SelectItem key={option.value} value={option.value}>
                {option.label}
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    </div>
  );
}

function CheckboxPreference(props: {
  checked: boolean;
  description: string;
  disabled?: boolean;
  label: string;
  onCheckedChange: (checked: boolean) => void;
}) {
  return (
    <Checkbox
      checked={props.checked}
      disabled={props.disabled}
      labelProps={{ className: 'items-start' }}
      onCheckedChange={(checked) => props.onCheckedChange(checked === true)}
    >
      <span className="flex min-w-0 flex-col gap-0.5">
        <span className="text-sm font-medium text-foreground">
          {props.label}
        </span>
        <span className="text-xs text-muted-foreground">
          {props.description}
        </span>
      </span>
    </Checkbox>
  );
}

function PreferencesStateBadge(props: {
  hasChanges: boolean;
  saveState: WorkspacePreferencesSaveState;
}) {
  if (props.saveState === 'saving') {
    return (
      <Badge variant="warning" size="sm">
        Saving
      </Badge>
    );
  }

  if (props.saveState === 'error') {
    return (
      <Badge variant="negative" size="sm">
        Needs attention
      </Badge>
    );
  }

  if (props.hasChanges) {
    return (
      <Badge variant="warning" size="sm">
        Unsaved changes
      </Badge>
    );
  }

  return (
    <Badge variant="positive" size="sm">
      Saved
    </Badge>
  );
}

function areWorkspacePreferencesValuesEqual(
  left: WorkspacePreferencesValues,
  right: WorkspacePreferencesValues
) {
  return (
    left.autoFollowTerminal === right.autoFollowTerminal &&
    left.defaultView === right.defaultView &&
    left.notifyOnCompletion === right.notifyOnCompletion &&
    left.notifyOnPrompt === right.notifyOnPrompt &&
    left.sidebarDefault === right.sidebarDefault &&
    left.terminalScale === right.terminalScale &&
    left.theme === right.theme
  );
}

function isPreferenceTab(
  value: string
): value is (typeof preferenceTabs)[number]['value'] {
  return preferenceTabs.some((tab) => tab.value === value);
}

